<?php
namespace App\Services\Localization;use App\Models\{TranslationEntry,User};use Illuminate\Support\Facades\File;
class TranslationManagerService{public function importFromLangFiles(?User $actor=null):int{$count=0;foreach(config('bikube_locales.supported',[]) as $locale=>$name){$file=lang_path("{$locale}/bikube.php");if(!File::exists($file))continue;foreach($this->flatten(require $file) as $key=>$value){$entry=TranslationEntry::updateOrCreate(['group'=>'bikube','key'=>$key,'locale'=>$locale],['value'=>$value,'status'=>'reviewed']);$entry->events()->create(['actor_id'=>$actor?->id,'event_type'=>'imported','description'=>'Imported from UTF-8 lang file.','created_at'=>now()]);$count++;}}return $count;}public function getMissingTranslations():array{$base=$this->flatten(require lang_path('en/bikube.php'));$out=[];foreach(array_keys(config('bikube_locales.supported',[])) as $locale){$values=File::exists(lang_path("{$locale}/bikube.php"))?$this->flatten(require lang_path("{$locale}/bikube.php")):[];$out[$locale]=array_values(array_diff(array_keys($base),array_keys($values)));}return $out;}public function updateTranslation(string $group,string $key,string $locale,string $value,User $actor):TranslationEntry{$e=TranslationEntry::updateOrCreate(compact('group','key','locale'),['value'=>$value,'status'=>'draft']);$e->events()->create(['actor_id'=>$actor->id,'event_type'=>'updated','description'=>'Translation updated.','created_at'=>now()]);return $e;}public function approveTranslation(TranslationEntry $e,User $actor):TranslationEntry{$e->update(['status'=>'approved','approved_by_id'=>$actor->id,'approved_at'=>now()]);$e->events()->create(['actor_id'=>$actor->id,'event_type'=>'approved','description'=>'Translation approved.','created_at'=>now()]);return $e->refresh();}public function getCoverageReport():array{$base=count($this->flatten(require lang_path('en/bikube.php')));$missing=$this->getMissingTranslations();return collect($missing)->map(fn($m,$l)=>['locale'=>$l,'total'=>$base,'missing'=>count($m),'coverage'=>$base?round((($base-count($m))/$base)*100,1):100])->values()->all();}public function scanHardcodedUiStrings():array{$hits=[];foreach(['app/Filament','resources/views','app/Http/Controllers','app/Services'] as $dir){foreach(File::allFiles(base_path($dir)) as $file){foreach(file($file->getPathname()) as $line=>$text){preg_match_all("/[\"'][A-Z][^\"']{2,}[\"']/", $text,$matches);foreach($matches[0] as $match)$hits[]=['file'=>$file->getRelativePathname(),'line'=>$line+1,'snippet'=>$match,'severity'=>str_starts_with($dir,'resources')?'high':'medium'];}}}return $hits;}private function flatten(array $data,string $prefix=''):array{$out=[];foreach($data as $k=>$v){$key=$prefix===''?$k:"{$prefix}.{$k}";if(is_array($v))$out+=$this->flatten($v,$key);else $out[$key]=(string)$v;}return $out;}}
